class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        hash_map = {}
        for i in range(len(nums)):
            if target - nums[i] in hash_map:
                return [hash_map[target-nums[i]], i]
            hash_map[nums[i]] = i

class Solution:
  def lengthOfLongestSubstring(self, s: str) -> int:
        mx, start, chars = 0, 0, {}

        for i in range(len(s)):

            if s[i] in chars and start <= chars[s[i]]:
                start = chars[s[i]] + 1

            else:
                mx = max(mx, i - start + 1)

            chars[s[i]] = i

        return mx

class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        arr = sorted(nums1 + nums2)
        if len(arr) % 2 == 0: return (arr[len(arr) // 2] + arr[len(arr) // 2 - 1]) / 2
        else: return arr[len(arr) // 2]

class Solution:
    def longestPalindrome(self, s: str) -> str:

        # Function to expand around center
        def expand_from_center(left_index, right_index):

            while (
                left_index >= 0
                and right_index < len(s)
                and s[left_index] == s[right_index]
            ):

                left_index -= 1
                right_index += 1

            # Return valid palindrome
            return s[left_index + 1 : right_index]

        all_palindromes = []

        # Check odd length palindromes
        for center in range(len(s)):
            palindrome = expand_from_center(center, center)
            all_palindromes.append(palindrome)

        # Check even length palindromes
        for center in range(len(s) - 1):

            if s[center] == s[center + 1]:

                palindrome = expand_from_center(center, center + 1)

                all_palindromes.append(palindrome)

        # Return longest palindrome
        return max(all_palindromes, key=len)

class Solution:
    def convert(self, s, numRows):
        if numRows == 1 or numRows >= len(s): return s
        row, direction, res = 0, -1, [""] * numRows
        for char in s:
            res[row] += char
            if row == 0 or row == numRows - 1: direction *= -1 
            row += direction
        return "".join(res)

